<?php $c=current_customer(); $rows=[]; try{$st=db()->prepare('SELECT s.*,p.name product_name,p.type FROM services s LEFT JOIN products p ON p.id=s.product_id WHERE s.customer_id=? ORDER BY s.id DESC');$st->execute([$c['id']]);$rows=$st->fetchAll();}catch(Throwable $e){} ?>
<div class="customer-panel-card"><h2>Hizmetlerim</h2><p>Hosting, VPS, web tasarım, SEO ve diğer Ahost One hizmetleriniz.</p></div><div class="customer-panel-card"><table class="table-like"><tr><th>Ürün</th><th>Tip</th><th>Domain</th><th>Durum</th><th>Ödeme Döngüsü</th><th>Sonraki Ödeme</th><th>İşlem</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['product_name']?:'Özel Hizmet') ?></td><td><?= e($r['type']) ?></td><td><?= e($r['domain']) ?></td><td><?= e($r['status']) ?></td><td><?= e($r['billing_cycle']) ?></td><td><?= e($r['next_due_date']) ?></td><td><a class="cp-link" href="<?= url('client/services/view?id='.(int)$r['id']) ?>">Yönet</a> · <a class="cp-link" href="<?= url('client/support') ?>">Destek</a></td></tr><?php endforeach; if(!$rows): ?><tr><td colspan="7">Aktif hizmetiniz yok.</td></tr><?php endif; ?></table></div>
